//! Pre-recorded valid move sequences generated by the nimzovich engine.

use nimzovich_engine::{
    api::{do_move, new_game},
    move_gen::init_move_tables,
    on_chain::{CompactBoard, CASTLE_BK, CASTLE_BQ, CASTLE_WK, CASTLE_WQ},
};

/// A valid move with its UCI encoding and the resulting board state.
pub struct ValidMove {
    pub uci: [u8; 5],
    pub next_board: [u8; 68],
}

/// Generate a 100-move valid game sequence using the chess engine.
/// Returns a vector of ValidMove where each entry contains the UCI move
/// and the CompactBoard state AFTER that move is applied.
pub fn generate_100_move_sequence() -> Vec<ValidMove> {
    let mut game = new_game();
    init_move_tables(&mut game);

    let mut result = Vec::with_capacity(100);

    for i in 0..100 {
        let (src, dst, uci) = if i % 2 == 0 {
            // White turn
            if (i / 2) % 2 == 0 {
                // g1 (6) to f3 (21)
                (6, 21, *b"g1f3\0")
            } else {
                // f3 (21) to g1 (6)
                (21, 6, *b"f3g1\0")
            }
        } else {
            // Black turn
            if (i / 2) % 2 == 0 {
                // g8 (62) to f6 (45)
                (62, 45, *b"g8f6\0")
            } else {
                // f6 (45) to g8 (62)
                (45, 62, *b"f6g8\0")
            }
        };

        // Apply move to engine state
        let _ = do_move(&mut game, src, dst, true);

        // Build CompactBoard from current game state
        let cb = CompactBoard {
            squares: game.board,
            castling: CASTLE_WK | CASTLE_WQ | CASTLE_BK | CASTLE_BQ,
            ep_target: game.en_passant_target.unwrap_or(-1),
            side_to_move: if game.move_counter % 2 == 0 { 1 } else { -1 },
            _pad: 0,
        };

        result.push(ValidMove {
            uci,
            next_board: cb.to_bytes(),
        });
    }

    result
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_100_move_sequence() {
        let seq = generate_100_move_sequence();
        assert_eq!(seq.len(), 100);
        for (i, vm) in seq.iter().enumerate() {
            let uci_str = std::str::from_utf8(&vm.uci[..4]).unwrap_or("error");
            println!("Move {}: {}", i + 1, uci_str);
        }
    }
}
